        parts: list[str] = []
        for key in ("parts", "content"):
            if key in value:
                parts.extend(extract_gemini_parts(value[key]))
        return parts
    return []


def find_first_mapping_with_keys(value: Any, keys: set[str]) -> dict[str, Any] | None:
    if isinstance(value, dict):
        if keys & set(value.keys()):
